### useEffect

Executa cĂłdigo quando o componente monta ou quando dependĂȘncias mudam.

```javascript
import React, {useState, useEffect} from ''react'';

const MyComponent = () => {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Executado quando componente monta
    fetchData();
  }, []); // [] = executar apenas uma vez

  useEffect(() => {
    // Executado quando ''data'' muda
    console.log(''Data mudou:'', data);
  }, [data]);

